var heb_ch_1_Verses = [
  {num:1,words:[["O le Atua, o le na fetalai mai anamua i o tatou tamā e le au perofeta,", "God,"], ["na auaua'i mai i togafiti eseese,", "who at sundry times and in divers manners spake in time past unto the fathers by the prophets,"]]},
  {num:2,words:[["ua fetalai mai o ia ia i tatou i nei ona aso e gata ai e lona Alo,", "Hath in these last days spoken unto us by his Son,"], ["o le ua tofia e ia e fai mea uma lava mona tofi,", "whom he hath appointed heir of all things,"], ["na ia faia foi e ia mea uma;", "by whom also he made the worlds;"]]},
  {num:3,words:[["o ia o le pupula o lona mamalu ma ua matuā tusa lava ma ia,", "Who being the brightness of his glory,"], ["o loo o faatumauina e ia mea uma lava i lana afioga mana,", "and the express image of his person,"], ["na ia faamamāina e ia lava a tatou agasala,", "and upholding all things by the word of his power, when he had by himself purged our sins,"], ["ona nofo ai lea o ia i le itu taumatau o lē Silisili ese o i lugā;", "sat down on the right hand of the Majesty on high;"]]},
  {num:4,words:[["ua faapea ona silisili ese o ia i agelu,", "Being made so much better than the angels,"], ["pei ona sili o lona suafa ua maua i o latou.", "as he hath by inheritance obtained a more excellent name than they."]]},
  {num:5,words:[["Auā o anafea ea na fetalai atu ai o ia i se tasi o le au agelu,", "For unto which of the angels said he at any time,"], ["O lo'u Atalii oe,", "Thou art my Son,"], ["ua ou fanaua oe i le aso nei; i le ma lea,", "this day have I begotten thee? And again,"], ["E fai a'u mona Tamā,", "I will be to him a Father,"], ["e fai foi o ia mo'u Atalii?", "and he shall be to me a Son?"]]},
  {num:6,words:[["Ua faapea mai foi o ia i lona toe au mai o lana ulumatua i le lalolagi,", "And again, when he bringeth in the firstbegotten into the world,"], ["Ma ia ifo agelu uma lava a le Atua ia te ia.", "he saith, And let all the angels of God worship him."]]},
  {num:7,words:[["O agelu foi ua fetalai mai ai o ia,", "And of the angels he saith,"], ["Ua faia e ia ana agelu o matagi,", "Who maketh his angels spirits,"], ["ma ana auauna o le afi mumū;", "and his ministers a flame of fire."]]},
  {num:8,words:[["a ua faapea mai i le Alo,", "But unto the Son he saith,"], ["O lou nofoālii,", "Thy throne,"], ["le Atua e, faavavau faavavau lava lea;", "O God,"], ["o le tootoo o lou malo,", "is for ever and ever:"], ["o le tootoo o le amiotonu lea.", "a sceptre of righteousness is the sceptre of thy kingdom."]]},
  {num:9,words:[["Ua e fiafia i le amiotonu,", "Thou hast loved righteousness,"], ["a ua e 'ino'ino i le amio leaga;", "and hated iniquity;"], ["o le mea lea,", "therefore God,"], ["ua faauuina ai oe e le Atua,", "even thy God,"], ["o lou lava Atua i le suāuu o le olioli e sili i e tou te faatasi.", "hath anointed thee with the oil of gladness above thy fellows."]]},
  {num:10,words:[["I le ma lea,", "And,"], ["Le Alii e,", "Thou,"], ["na e faavaeina le lalolagi i le amataga,", "Lord, in the beginning hast laid the foundation of the earth;"], ["o lagi foi o galuega ia a ou aao;", "and the heavens are the works of thine hands:"]]},
  {num:11,words:[["e faaumatia ia mea,", "They shall perish;"], ["a o oe e te tumau pea;", "but thou remainest;"], ["e pala ia mea uma lava pei o se ofu,", "and they all shall wax old as doth a garment;"]]},
  {num:12,words:[["pei o se ie pulupulu e te taataaia,", "And as a vesture shalt thou fold them up,"], ["e liua foi ia;", "and they shall be changed:"], ["a o oe, e te le liliu lava,", "but thou art the same,"], ["e leai foi se iuga i ou tausaga.", "and thy years shall not fail."]]},
  {num:13,words:[["A o anafea na fetalai atu ai o ia i se tasi o le au agelu,", "But to which of the angels said he at any time,"], ["Ina nofo ia oe i lo'u itu taumatau,", "Sit on my right hand,"], ["seia ou faia e ua fai oe mo latou fili ma mea e tu ai ou vae?", "until I make thine enemies thy footstool?"]]},
  {num:14,words:[["E le o agaga e auauna ea i latou uma,", "Are they not all ministering spirits,"], ["ua aauina e auauna ona o i latou o e a maua le ola?", "sent forth to minister for them who shall be heirs of salvation?"]]},
];
